How-To-Repeat: 	#include <stdio.h>
	#include <fcntl.h>
	#include <stdlib.h>
	#include <string.h>
	#include <errno.h>

	main(int cc, char **vv)
	{
	int fd;
	char *fn;

	if(cc > 1)
	      fn = vv[1];
	else
		fn = "lock";
	fd = open(fn, O_WRONLY|O_CREAT|O_EXCL, 0666);
	if(fd < 0) {
	      int err = errno;
	      fprintf(stderr, "%d - %s\n", err, strerror(err));
	}
	exit(0);
	}
